/*
 * Base color tokens (--bg, --text, --accent, …) come from @qwixl/skin-default
 * (default.css / dark.css / high-contrast.css via data-atom-skin).
 * This file only adds shell-specific derived tokens.
 */
:root {
  --text-muted: color-mix(in srgb, var(--text-dim) 70%, var(--bg));
  --accent-strong: color-mix(in srgb, var(--accent) 85%, #000);
  --good-soft: color-mix(in srgb, var(--good) 10%, transparent);
  --warn-soft: color-mix(in srgb, var(--warn) 10%, transparent);
  --bad-soft: color-mix(in srgb, var(--bad) 9%, transparent);
  --chrome: #6d4fd8;
  --chrome-soft: rgba(109, 79, 216, 0.08);
  --radius-sm: 8px;
  --shadow-sm: 0 1px 2px rgba(16, 24, 40, 0.05);
  --shadow-md: 0 4px 12px rgba(16, 24, 40, 0.08);
  --shadow-lg: 0 20px 60px rgba(16, 24, 40, 0.18);
  --font-mono: ui-monospace, "Cascadia Code", Consolas, monospace;
  font-family: var(--atom-font-sans, "Segoe UI", system-ui, sans-serif);
  color-scheme: light;
}

[data-atom-skin="dark"],
[data-atom-skin="high-contrast"] {
  --chrome: #8f75f0;
  --chrome-soft: rgba(143, 117, 240, 0.14);
  --shadow-sm: 0 1px 2px rgba(0, 0, 0, 0.3);
  --shadow-md: 0 4px 12px rgba(0, 0, 0, 0.4);
  --shadow-lg: 0 20px 60px rgba(0, 0, 0, 0.55);
  color-scheme: dark;
}

[data-atom-skin="dark"],
[data-atom-skin="high-contrast"] {
  --chrome: #8f75f0;
  --chrome-soft: rgba(143, 117, 240, 0.14);
  --shadow-sm: 0 1px 2px rgba(0, 0, 0, 0.3);
  --shadow-md: 0 4px 12px rgba(0, 0, 0, 0.4);
  --shadow-lg: 0 20px 60px rgba(0, 0, 0, 0.55);
  --on-accent: #0b1220;
  color-scheme: dark;
}

:root {
  --on-accent: #ffffff;
}

