/* ---------- comms view ---------- */

.comms-view {
  flex: 1;
  min-width: 0;
  min-height: 0;
  display: flex;
  flex-direction: column;
  background: var(--bg);
}

.comms-toolbar {
  flex: none;
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 16px;
  padding: 16px 24px;
  border-bottom: 1px solid var(--border);
  background: var(--bg-raised);
}

.comms-toolbar-title h2 {
  margin: 0;
  font-size: 18px;
  font-weight: 650;
  letter-spacing: -0.02em;
}

.comms-toolbar-sub {
  margin: 4px 0 0;
  font-size: 12px;
  color: var(--text-dim);
  line-height: 1.5;
}

.comms-toolbar-sub code {
  font-family: var(--font-mono);
  font-size: 11px;
}

.comms-status-error {
  color: var(--bad);
}

.comms-toolbar-actions {
  display: flex;
  gap: 8px;
  flex-shrink: 0;
}

.comms-toolbar-actions button {
  background: var(--bg-raised);
  border: 1px solid var(--border-strong);
  border-radius: var(--radius-sm);
  color: var(--text);
  padding: 8px 14px;
  font-size: 13px;
  font-weight: 500;
  cursor: pointer;
  transition: border-color 120ms, background 120ms, color 120ms;
}

.comms-toolbar-actions button:hover:not(:disabled) {
  border-color: var(--accent);
  color: var(--accent);
}

.comms-toolbar-actions button.is-active {
  background: var(--accent-soft);
  border-color: var(--accent);
  color: var(--accent);
}

.comms-toolbar-actions button:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.comms-setup {
  flex: none;
  display: grid;
