}

.comms-inline-actions {
  display: flex;
  gap: 8px;
  flex-wrap: wrap;
}

.comms-inline-actions button {
  background: var(--bg-raised);
  border: 1px solid var(--border-strong);
  border-radius: var(--radius-sm);
  color: var(--text);
  padding: 7px 12px;
