/* ---------- demo walkthrough ---------- */

.demo-walkthrough {
  flex: none;
  padding: 16px 24px 20px;
  border-bottom: 1px solid var(--border);
  background: linear-gradient(180deg, var(--accent-soft), var(--bg-raised));
}

.demo-walkthrough-head h3 {
  margin: 0 0 6px;
  font-size: 15px;
  font-weight: 650;
}

.demo-walkthrough-head p {
  margin: 0;
  font-size: 13px;
  color: var(--text-dim);
  line-height: 1.55;
  max-width: 62ch;
}

.demo-walkthrough-steps {
  list-style: none;
  margin: 16px 0 0;
  padding: 0;
  display: flex;
  gap: 8px;
  flex-wrap: wrap;
}

.demo-walkthrough-step {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px 12px;
  border-radius: 999px;
  border: 1px solid var(--border);
  background: var(--bg-raised);
  font-size: 12px;
  font-weight: 500;
  color: var(--text-dim);
}

.demo-walkthrough-step.is-active {
  border-color: var(--accent);
  background: var(--bg-raised);
  color: var(--accent);
  box-shadow: var(--shadow-sm);
}

.demo-walkthrough-step.is-done {
  border-color: color-mix(in srgb, var(--good) 35%, var(--border));
  color: var(--good);
}

.demo-walkthrough-step-num {
  width: 20px;
  height: 20px;
  border-radius: 50%;
  display: grid;
  place-items: center;
  font-size: 11px;
  font-weight: 700;
  background: var(--bg-inset);
}

.demo-walkthrough-step.is-active .demo-walkthrough-step-num {
  background: var(--accent);
  color: var(--on-accent);
}

.demo-walkthrough-step.is-done .demo-walkthrough-step-num {
  background: var(--good-soft);
  color: var(--good);
}

.demo-walkthrough-action {
  margin: 14px 0 0;
